// Classic round analog wall clock — replicad/BREP.
// ~80 mm diameter, ~12 mm thick. Back face on z=0, front face up.
// Showcases BREP.circularPattern for 12 hour markers + chamfered bezel.
const { BREP } = api;

// --- Back plate: a low cylinder, chamfered on its outer-bottom rim. ---
// The back plate base is at z=0, top at z=4. We chamfer the bottom rim
// (parallelToPlane:'XY' + maxZ to lock onto the bottom circular edge).
const backPlateRaw = BREP.cylinder(40, 4);
const backPlate = BREP.label(
  backPlateRaw.chamfer(0.8, { maxZ: 0.01, parallelToPlane: 'XY' }),
  'back',
);

// --- Outer bezel ring: a torus around the perimeter, sitting at z=4. ---
// BREP.torus(major, minor) — major=38, minor=4 puts the ring just inside
// the back plate's outer rim with its centerline at z=4.
const bezel = BREP.label(
  BREP.torus(38, 4).translate([0, 0, 4]),
  'bezel',
);

// --- Dial face: a recessed disc inside the bezel, sitting at z=7..8. ---
const dial = BREP.label(
  BREP.cylinder(34, 1).translate([0, 0, 7]),
  'dial',
);

// --- Hour markers: ONE seed at the 12 o'clock position, then circularPattern
// stamps 12 copies evenly around Z. The seed sits on top of the dial.
// radius:0 because the seed is already translated to the desired radius;
// circularPattern then just rotates copies around the Z axis.
const markerSeed = BREP.label(
  BREP.box([1.5, 4, 1.5]).translate([0, 30, 8]),
  'hour_marker',
);
const hourMarkers = BREP.circularPattern(markerSeed, 12, {
  radius: 0,
  axis: [0, 0, 1],
});

// --- Hour hand: thicker + shorter, pointing roughly up (toward 12). ---
const hourHand = BREP.label(
  BREP.box([2, 20, 1]).translate([0, 7, 9]),
  'hour_hand',
);

// --- Minute hand: thinner + longer, rotated to point at "1:30-ish". ---
const minuteHand = BREP.label(
  BREP.box([1.2, 28, 1]).translate([0, 11, 9.5]).rotate(-45, [0, 0, 1]),
  'minute_hand',
);

// --- Center spindle: a small cylinder hiding the hand-pivot. ---
const spindle = BREP.label(
  BREP.cylinder(2, 1.5).translate([0, 0, 10]),
  'spindle',
);

// --- Final assembly ---
return BREP.fuseAll([
  backPlate,
  bezel,
  dial,
  hourMarkers,
  hourHand,
  minuteHand,
  spindle,
]);

